import base64
import pathlib
import subprocess
import textwrap
import time

root = pathlib.Path("/marimo/yolo_code")
files = [('misc/train_only_p3_edge.py', ''), ('models_related/models_config/yolov8/yolov8_varroa_compare_baseline_p3_api_boxgrad_ensimam.yaml', ''), ('models_related/models_config/yolov8/yolov8_varroa_compare_baseline_p3_api_boxgrad_edge_ensimam.yaml', ''), ('models_related/models_config/yolov8/yolov8_varroa_compare_baseline_p3_api_boxgrad_edge_pooling.yaml', '')]

if not root.exists():
    raise SystemExit("ERROR: /marimo/yolo_code does not exist")

print("=== sync files ===")
for rel, data in files:
    path = root / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(base64.b64decode(data))
    print("wrote", path, path.stat().st_size)

script = root / "misc/train_only_p3_edge.py"
log = root / "train_only_p3_edge.nohup.log"
pidfile = root / "train_only_p3_edge.pid"

print("script exists", script.exists())
print("yaml exists", all((root / rel).exists() for rel, _ in files[1:]))

print("=== launch ===")
launch = textwrap.dedent("""
    cd /marimo/yolo_code
    if [ -d .venv ]; then
      . .venv/bin/activate
    else
      . /home/duylearch/miniconda3/bin/activate ml2
    fi
    nohup python misc/train_only_p3_edge.py > train_only_p3_edge.nohup.log 2>&1 &
    echo $! > train_only_p3_edge.pid
""")
r = subprocess.run(["bash", "-lc", launch], text=True, capture_output=True)
print(r.stdout, end="")
print(r.stderr, end="")
print("launch exit", r.returncode)
if r.returncode != 0:
    raise SystemExit("ERROR: launch failed")

pid = pidfile.read_text().strip() if pidfile.exists() else ""
print("pid", pid)
time.sleep(8)
if pid:
    ps = subprocess.run(["ps", "-p", pid, "-o", "pid,ppid,stat,etime,cmd"], text=True, capture_output=True)
    print("ps rc", ps.returncode)
    print(ps.stdout + ps.stderr)
print("log exists", log.exists())
if log.exists():
    lines = log.read_text(errors="replace").splitlines()
    print("log lines", len(lines))
    print("--- tail ---")
    print("\n".join(lines[-80:]))
